import React, { useState, useEffect } from "react";
import axios from "axios";
import { ThemeProvider, useTheme } from "./contexts/ThemeContext";

// Layout & Pages
import Layout from "./components/layout/Layout";
import AuthPage from "./pages/AuthPage";
import DashboardPage from "./pages/DashboardPage";
import GroupsPage from "./pages/GroupsPage";
import FilesPage from "./pages/FilesPage";
import PeersPage from "./pages/PeersPage";
import UploadPage from "./pages/UploadPage";
import TransfersPage from "./pages/TransfersPage";
import TransferProgress from "./components/ui/TransferProgress";
import WebRTCHandler from "./utils/webrtc";

import "./App.css";

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const getAPIBaseURL = () => {
  const hostname = window.location.hostname;
  const protocol = window.location.protocol || 'http:';
  if (process.env.REACT_APP_API_URL) return process.env.REACT_APP_API_URL;
  return `${protocol}//${hostname}:5000/api`;
};

const BASE_API = getAPIBaseURL();
axios.defaults.baseURL = BASE_API;
const API = axios.create({ baseURL: BASE_API, withCredentials: true });

function AppContent() {
  const { toggleTheme, isDark } = useTheme();
  const [token, setToken] = useState(localStorage.getItem("token") || "");
  const [user, setUser] = useState(null);

  // Navigation State
  const [view, setView] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Form states
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");
  const [regUsername, setRegUsername] = useState("");
  const [regEmail, setRegEmail] = useState("");
  const [regPassword, setRegPassword] = useState("");
  const [isLogin, setIsLogin] = useState(true);

  // Global App States
  const [loading, setLoading] = useState(false);
  const [notification, setNotification] = useState(null);

  // Data states
  const [files, setFiles] = useState([]); // Local received files
  const [peers, setPeers] = useState([]);
  const [stats, setStats] = useState({ fileCount: 0, peersOnline: 0 });

  // Profile & Settings
  const [editUsername, setEditUsername] = useState("");
  const [editEmail, setEditEmail] = useState("");
  const [settingsTheme, setSettingsTheme] = useState("light");
  const [emailNotifications, setEmailNotifications] = useState(true);

  // Transfer states for TransferProgress visualizer
  const [activeTransfers, setActiveTransfers] = useState([]);

  // WebRTC
  const [webrtc, setWebrtc] = useState(null);
  const [webrtcPeers, setWebrtcPeers] = useState([]);

  /** ======================
   *  INIT & REAL-TIME
   ======================== */
  useEffect(() => {
    if (token) {
      API.defaults.headers.common["Authorization"] = `Bearer ${token}`;
      fetchUser();
    } else {
      const savedToken = localStorage.getItem("token");
      if (savedToken) {
        setToken(savedToken);
        API.defaults.headers.common["Authorization"] = `Bearer ${savedToken}`;
      }
    }
  }, [token]);

  useEffect(() => {
    if (user) {
      const interval = setInterval(() => {
        fetchPeers();
      }, 5000);

      // Initialize WebRTC
      const signalingUrl = getAPIBaseURL().replace('5000/api', '5002');
      const handler = new WebRTCHandler(
        signalingUrl,
        user._id,
        user.username,
        (peersList) => {
          setWebrtcPeers(peersList);
        },
        (progressUpdate) => {
          setActiveTransfers(prev => {
            const index = prev.findIndex(t => t.id === progressUpdate.id);
            if (index >= 0) {
              const updated = [...prev];
              updated[index] = progressUpdate;
              // Add to local files if complete and download
              if (progressUpdate.status === 'complete' && progressUpdate.type === 'download') {
                  setFiles(curr => {
                      const exists = curr.find(f => f.name === progressUpdate.fileName);
                      if (!exists) {
                          return [{
                              id: Date.now() + Math.random(),
                              name: progressUpdate.fileName,
                              size: progressUpdate.totalSize,
                              receivedAt: new Date().toISOString()
                          }, ...curr];
                      }
                      return curr;
                  });
              }
              // Remove complete transfers after 3 seconds
              if (progressUpdate.status === 'complete') {
                setTimeout(() => {
                  setActiveTransfers(curr => curr.filter(t => t.id !== progressUpdate.id));
                }, 3000);
              }
              return updated;
            } else {
              if (progressUpdate.status === 'complete') return prev; // don't add completed ones right away
              return [...prev, progressUpdate];
            }
          });
        }
      );
      setWebrtc(handler);

      return () => {
        clearInterval(interval);
        handler.disconnect();
      };
    }
  }, [user]); // user is enough dependency here since we just want it once on login


  /** ======================
   *  NOTIFICATIONS
   ======================== */
  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 4000);
  };

  /** ======================
   *  API FETCHERS
   ======================== */
  const fetchUser = async () => {
    try {
      const res = await API.get("/auth/me");
      setUser(res.data);
      setEditUsername(res.data.username);
      setEditEmail(res.data.email);
      setSettingsTheme(res.data.theme || "light");
      setEmailNotifications(res.data.emailNotifications !== false);

      await fetchPeers();
    } catch (err) {
      if (err.response?.status === 401 || err.response?.status === 403) logout();
    }
  };

  const fetchPeers = async () => {
    try {
      const res = await API.get("/peers");
      setPeers(res.data);
      setStats({ fileCount: files.length, peersOnline: res.data.length });
    } catch (err) {}
  };

  /** ======================
   *  AUTH COMMANDS
   ======================== */
  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const endpoint = isLogin ? "/auth/login" : "/auth/register";
      const data = isLogin
        ? { email: loginEmail, password: loginPassword }
        : { username: regUsername, email: regEmail, password: regPassword };

      const res = await API.post(endpoint, data);

      setToken(res.data.token);
      localStorage.setItem("token", res.data.token);
      setUser(res.data.user);
      setView("dashboard");
      notify("Welcome!");
    } catch (err) {
      notify(err.response?.data?.error || "Authentication failed", "error");
    }
    setLoading(false);
  };

  const logout = () => {
    setToken("");
    setUser(null);
    localStorage.removeItem("token");
    delete API.defaults.headers.common["Authorization"];
    notify("Logged out");
  };

  /** ======================
   *  PEER LOGIC
   ======================== */
  const connectToPeer = async (peerId, peerName) => {
    setLoading(true);
    try {
      // First register it with central API as intended
      await API.post("/peers/connect", { peerId });
      notify(`Connected to ${peerName}!`);
      fetchPeers();

      // Try negotiating direct WebRTC if they are in signaling layer
      if (webrtc) {
        const targetWrtpPeer = webrtcPeers.find(p => p.peerId === peerId || p.peerName === peerName);
        if (targetWrtpPeer) {
          webrtc.connectToPeer(targetWrtpPeer.socketId);
        }
      }
    } catch (err) {
      notify(err.response?.data?.error || "Failed to connect", "error");
    }
    setLoading(false);
  };

  /** ======================
   *  TRANSFERS & FILES LOGIC
   ======================== */
  const deleteFile = async (id) => {
    if (!window.confirm("Delete this local file record?")) return;
    setFiles(curr => curr.filter(f => f.id !== id));
    notify("Local file record deleted");
  };

  /** ======================
   *  FORMATTERS
   ======================== */
  const formatSize = (bytes) => {
    if (!bytes) return "0 MB";
    const mb = bytes / (1024 * 1024);
    if (mb >= 1024) return `${(mb / 1024).toFixed(2)} GB`;
    if (mb >= 1) return `${mb.toFixed(2)} MB`;
    return `${(bytes / 1024).toFixed(2)} KB`;
  };

  const formatDate = (d) => new Date(d).toLocaleString();


  /** ======================
   *  RENDER APP
   ======================== */
  if (!token || !user) {
    return (
      <AuthPage 
        isLogin={isLogin} setIsLogin={setIsLogin}
        loginEmail={loginEmail} setLoginEmail={setLoginEmail}
        loginPassword={loginPassword} setLoginPassword={setLoginPassword}
        regUsername={regUsername} setRegUsername={setRegUsername}
        regEmail={regEmail} setRegEmail={setRegEmail}
        regPassword={regPassword} setRegPassword={setRegPassword}
        handleAuth={handleAuth} loading={loading}
        notification={notification}
      />
    );
  }

  return (
    <Layout
      user={user}
      isDark={isDark}
      toggleTheme={toggleTheme}
      onLogout={logout}
      onProfileClick={() => setView("profile")}
      onSettingsClick={() => setView("settings")}
      sidebarOpen={sidebarOpen}
      setSidebarOpen={setSidebarOpen}
      view={view}
      setView={setView}
      groups={[]}
      peers={webrtcPeers.length > 0 ? webrtcPeers : peers}
      selectedGroup={null}
      selectGroup={() => {}}
      activeTransfers={activeTransfers.length}
    >

      {view === "dashboard" && (
        <DashboardPage 
          stats={stats} 
          peersCount={webrtcPeers.length > 0 ? webrtcPeers.length : peers.length} 
          groups={[]}
          setView={setView}
          selectGroup={() => {}}
          fetchStats={() => {}}
        />
      )}

      {view === "files" && (
        <FilesPage
          files={files}
          deleteFile={deleteFile}
          formatSize={formatSize}
          formatDate={formatDate}
        />
      )}

      {view === "peers" && (
        <PeersPage
          peers={webrtcPeers.length > 0 ? webrtcPeers : peers} // prefer webrtc signalling server peers
          connectToPeer={connectToPeer}
          loading={loading}
        />
      )}

      {view === "upload" && (
          <UploadPage 
            peers={webrtcPeers}
            webrtc={webrtc}
            notify={notify}
            setView={setView}
          />
      )}

      {view === "transfers" && (
          <TransfersPage activeTransfers={activeTransfers} />
      )}

      {/* Global Notification */}
      {notification && (
        <div className={`notification ${notification.type}`}>
          {notification.msg}
        </div>
      )}
    </Layout>
  );
}

function App() {
  return (
    <ThemeProvider>
      <AppContent />
    </ThemeProvider>
  );
}

export default App;
